    	update accounts 
    	set 
    		is_active = 'N',
	        account_number = CONCAT('DELETED-', RIGHT(account_number, 4)),
	        billing_key = ${billingKey}
    	WHERE account_seq = #{accountSeq}

mapper.select:
SELECT o.order_seq AS orderSeq, o.order_no AS orderNo, buyer_store.store_seq AS storeSeq, partner_store.store_seq AS partnerSeq, o.total_amount AS totalAmount FROM orders o JOIN stores buyer_store ON buyer_store.user_seq = o.buyer_seq JOIN stores partner_store ON partner_store.user_seq = o.seller_seq WHERE buyer_store.store_seq = #{storeSeq} AND partner_store.store_seq = #{partnerSeq} AND o.order_seq IN
#{orderSeq}
AND NOT EXISTS ( SELECT 1 FROM payment_order_map pom JOIN payments p ON pom.payment_seq = p.payment_seq WHERE pom.order_seq = o.order_seq AND p.status = 'PAID' )
